/**
 * PM Plots Loader - SSOT Dynamic Visualization Loading
 * =====================================================
 *
 * Loads plot visualizations dynamically from plots-manifest.json.
 * Ensures Single Source of Truth - no hardcoded plot lists.
 *
 * Copyright (c) 2026 Andrew Keith Watts. All rights reserved.
 */

(function(global) {
    'use strict';

    const CONFIG = {
        MANIFEST_PATHS: [
            '../AutoGenerated/plots-manifest.json',
            '/AutoGenerated/plots-manifest.json',
            'AutoGenerated/plots-manifest.json'
        ],
        PLOTS_DIR: '../AutoGenerated/plots/',
        CACHE_TTL: 5 * 60 * 1000  // 5 minutes
    };

    const state = {
        manifest: null,
        lastLoad: 0,
        isLoading: false,
        loadError: null
    };

    /**
     * Load plots manifest from JSON
     */
    async function loadManifest() {
        // Check cache
        if (state.manifest && (Date.now() - state.lastLoad) < CONFIG.CACHE_TTL) {
            console.log('[PM-Plots] Using cached manifest');
            return state.manifest;
        }

        state.isLoading = true;
        state.loadError = null;

        // Try each path
        for (const path of CONFIG.MANIFEST_PATHS) {
            try {
                console.log(`[PM-Plots] Trying manifest path: ${path}`);
                const response = await fetch(path);

                if (!response.ok) continue;

                const text = await response.text();
                if (!text.trim().startsWith('{')) continue;

                const data = JSON.parse(text);

                // Validate structure
                if (data.plots && Array.isArray(data.plots)) {
                    state.manifest = data;
                    state.lastLoad = Date.now();
                    state.isLoading = false;
                    console.log(`[PM-Plots] Loaded manifest v${data.version} with ${data.total_plots} plots`);
                    return data;
                }
            } catch (e) {
                console.log(`[PM-Plots] Failed to load from ${path}:`, e.message);
            }
        }

        state.loadError = 'Could not load plots manifest';
        state.isLoading = false;
        return null;
    }

    /**
     * Render plots grid
     */
    function renderPlotsGrid(container, category = null) {
        if (!state.manifest) {
            container.innerHTML = '<p style="color: var(--text-muted);">Loading plots...</p>';
            return;
        }

        const plots = category
            ? state.manifest.plots.filter(p => p.category === category)
            : state.manifest.plots;

        if (plots.length === 0) {
            container.innerHTML = '<p style="color: var(--text-muted);">No plots available</p>';
            return;
        }

        const html = plots.map(plot => `
            <div class="plot-card" data-plot-id="${plot.id}">
                <div class="plot-image-wrapper">
                    <img
                        src="${CONFIG.PLOTS_DIR}${plot.file}"
                        alt="${plot.title}"
                        class="plot-thumbnail"
                        loading="lazy"
                        onclick="PMPlots.openLightbox('${plot.id}')"
                    />
                </div>
                <div class="plot-info">
                    <h3 class="plot-title">${plot.title}</h3>
                    <p class="plot-description">${plot.description}</p>
                    <div class="plot-meta">
                        <span class="plot-category">${plot.category}</span>
                        <span class="plot-version">v${plot.version}</span>
                        <span class="plot-size">${plot.size_kb}KB</span>
                    </div>
                </div>
            </div>
        `).join('');

        container.innerHTML = html;
    }

    /**
     * Render category navigation
     */
    function renderCategories(container) {
        if (!state.manifest || !state.manifest.categories) return;

        const html = Object.entries(state.manifest.categories).map(([key, cat]) => `
            <div class="category-card" onclick="PMPlots.filterByCategory('${key}')">
                <h3>${cat.title}</h3>
                <p>${cat.description}</p>
                <span class="category-count">${cat.count} plots</span>
            </div>
        `).join('');

        container.innerHTML = html;
    }

    /**
     * Open plot in lightbox
     */
    function openLightbox(plotId) {
        if (!state.manifest) return;

        const plot = state.manifest.plots.find(p => p.id === plotId);
        if (!plot) return;

        // Create lightbox if it doesn't exist
        let lightbox = document.getElementById('pm-plot-lightbox');
        if (!lightbox) {
            lightbox = document.createElement('div');
            lightbox.id = 'pm-plot-lightbox';
            lightbox.className = 'pm-lightbox';
            lightbox.innerHTML = `
                <div class="lightbox-content">
                    <button class="lightbox-close" onclick="PMPlots.closeLightbox()">&times;</button>
                    <img class="lightbox-image" src="" alt="">
                    <div class="lightbox-info">
                        <h2 class="lightbox-title"></h2>
                        <p class="lightbox-description"></p>
                    </div>
                </div>
            `;
            document.body.appendChild(lightbox);
        }

        // Update lightbox content
        lightbox.querySelector('.lightbox-image').src = CONFIG.PLOTS_DIR + plot.file;
        lightbox.querySelector('.lightbox-title').textContent = plot.title;
        lightbox.querySelector('.lightbox-description').textContent = plot.description;
        lightbox.classList.add('active');
        document.body.style.overflow = 'hidden';
    }

    /**
     * Close lightbox
     */
    function closeLightbox() {
        const lightbox = document.getElementById('pm-plot-lightbox');
        if (lightbox) {
            lightbox.classList.remove('active');
            document.body.style.overflow = '';
        }
    }

    /**
     * Filter plots by category
     */
    function filterByCategory(category) {
        const container = document.getElementById('plots-grid');
        if (container) {
            renderPlotsGrid(container, category);
        }
    }

    /**
     * Initialize plots viewer
     */
    async function init(options = {}) {
        const {
            plotsContainer = 'plots-grid',
            categoriesContainer = 'categories-grid',
            loadingIndicator = 'plots-loading'
        } = options;

        // Show loading
        const loadingEl = document.getElementById(loadingIndicator);
        if (loadingEl) loadingEl.style.display = 'block';

        // Load manifest
        const manifest = await loadManifest();

        // Hide loading
        if (loadingEl) loadingEl.style.display = 'none';

        if (!manifest) {
            console.error('[PM-Plots] Failed to load manifest');
            const container = document.getElementById(plotsContainer);
            if (container) {
                container.innerHTML = `
                    <div style="text-align: center; padding: 2rem; color: var(--text-muted);">
                        <h3>Could not load plots</h3>
                        <p>The plots manifest file is missing or inaccessible.</p>
                        <p><small>Run: python scripts/generate_all_plots.py</small></p>
                    </div>
                `;
            }
            return;
        }

        // Render plots
        const plotsEl = document.getElementById(plotsContainer);
        if (plotsEl) {
            renderPlotsGrid(plotsEl);
        }

        // Render categories
        const categoriesEl = document.getElementById(categoriesContainer);
        if (categoriesEl) {
            renderCategories(categoriesEl);
        }

        // Dispatch ready event
        document.dispatchEvent(new CustomEvent('pm-plots-ready', {
            detail: { manifest, plotCount: manifest.total_plots }
        }));
    }

    // Public API
    const PMPlots = {
        init,
        loadManifest,
        renderPlotsGrid,
        renderCategories,
        openLightbox,
        closeLightbox,
        filterByCategory,
        getManifest: () => state.manifest,
        getState: () => ({ ...state })
    };

    // Export
    if (typeof module !== 'undefined' && module.exports) {
        module.exports = PMPlots;
    } else {
        global.PMPlots = PMPlots;
    }

})(typeof window !== 'undefined' ? window : global);
